<?php
$pageTitle = 'Member Messaging';
$pageDescription = 'Stonefellow member messaging and segmented campaign composer for email and in-app notices.';
$pageClass = 'membership-page admin-catalog-page';
require __DIR__ . '/../includes/admin_catalog.php';
require_once __DIR__ . '/../includes/ops_scheduler_messaging.php';
if (($_SERVER['REQUEST_METHOD'] ?? 'GET') === 'POST') {
  if (!sf_verify_csrf($_POST['csrf_token'] ?? null)) { sf_admin_flash('error','Security check failed.'); sf_admin_redirect(); }
  $action=(string)($_POST['action']??'');
  if($action==='save_campaign'){ $id=sf_msg_save_campaign($_POST,(int)($_POST['id']??0)); sf_admin_flash($id?'success':'error',$id?'Message campaign saved.':'Campaign was not saved. Run migration 017.'); sf_admin_redirect($id?sf_url('admin/member-messaging.php?campaign_id='.$id):null); }
  if($action==='seed_recipients'){ $count=sf_msg_seed_recipients((int)($_POST['campaign_id']??0)); sf_admin_flash('success','Recipient queue prepared: '.$count.' added/confirmed.'); }
  if($action==='send_campaign'){ $r=sf_msg_send_campaign((int)($_POST['campaign_id']??0),500); sf_admin_flash('success','Send complete: '.(int)$r['processed'].' processed, '.(int)$r['sent'].' sent, '.(int)$r['failed'].' failed.'); }
  if($action==='send_due'){ $r=sf_msg_send_due(20); sf_admin_flash('success','Due message campaigns complete: '.(int)$r['campaigns'].' campaigns, '.(int)$r['sent'].' sent.'); }
  sf_admin_redirect(sf_url('admin/member-messaging.php'));
}
require __DIR__ . '/../includes/header.php';
$summary=sf_msg_summary();
$campaigns=sf_msg_campaigns(120);
$editId=(int)($_GET['campaign_id']??0);
$edit=$editId?sf_msg_campaign($editId):null;
$recipients=$editId&&sf_sched_table_exists('member_message_recipients')?sf_sched_fetch_all('SELECT r.*, u.email, u.display_name FROM member_message_recipients r LEFT JOIN users u ON u.id=r.user_id WHERE r.campaign_id=? ORDER BY r.created_at DESC LIMIT 120',[$editId]):[];
sf_admin_shell_start('Member Messaging', 'Campaign broadcasts v1', 'Compose member notices, choose safe audience filters, create in-app messages, queue email delivery, and track message performance.', 'member-messaging');
?>
