 notification</label><label class="sf-admin-check"><input type="checkbox" name="channel_in_app" value="1"<?= !isset($edit['channel_in_app'])||!empty($edit['channel_in_app'])?' checked':'' ?><?= sf_admin_form_disabled_attr() ?>> Create in-app message</label><label class="sf-admin-check"><input type="checkbox" name="honors_preferences" value="1"<?= !isset($edit['honors_preferences'])||!empty($edit['honors_preferences'])?' checked':'' ?><?= sf_admin_form_disabled_attr() ?>> Honor member preferences where available</label><div class="sf-admin-form-actions"><button type="submit"<?= sf_admin_form_disabled_attr() ?>>Save Campaign</button></div></form></aside>
</section>
